const endpoints = [
  { name: 'Production API', url: process.env.HEALTH_CHECK_API_URL || 'https://api.example.com/health' },
  { name: 'Production Web', url: process.env.HEALTH_CHECK_WEB_URL || 'https://app.example.com' },
  { name: 'Staging API', url: process.env.HEALTH_CHECK_STAGING_URL || 'https://staging-api.example.com/health' },
  { name: 'Auth Service', url: process.env.HEALTH_CHECK_AUTH_URL || 'https://auth.example.com/health' }
];

const results = [];
const downEndpoints = [];

for (const endpoint of endpoints) {
  const start = Date.now();
  try {
    const response = await fetch(endpoint.url, {
      method: 'GET',
      signal: AbortSignal.timeout(10000)
    });
    const responseTime = Date.now() - start;
    const isUp = response.status >= 200 && response.status < 400;
    results.push({
      name: endpoint.name,
      url: endpoint.url,
      status: isUp ? 'UP' : 'DOWN',
      statusCode: response.status,
      responseTime: responseTime
    });
    if (!isUp) {
      downEndpoints.push({ name: endpoint.name, url: endpoint.url, statusCode: response.status, responseTime: responseTime });
    }
  } catch (error) {
    const responseTime = Date.now() - start;
    results.push({
      name: endpoint.name,
      url: endpoint.url,
      status: 'DOWN',
      statusCode: 0,
      responseTime: responseTime,
      error: error.message
    });
    downEndpoints.push({ name: endpoint.name, url: endpoint.url, statusCode: 0, error: error.message, responseTime: responseTime });
  }
}

return [{
  json: {
    timestamp: new Date().toISOString(),
    totalEndpoints: endpoints.length,
    upCount: results.filter(r => r.status === 'UP').length,
    downCount: downEndpoints.length,
    hasDownEndpoints: downEndpoints.length > 0,
    results: results,
    downEndpoints: downEndpoints
  }
}];

